Какой антипаттерн здесь?
```js
async function processImage(imageData) {
  const worker = new Worker('image-worker.js')
  return new Promise((resolve) => {
    worker.onmessage = (e) => {
      resolve(e.data)
      worker.terminate()
    }
    worker.postMessage(imageData)
  })
}
```
